    //         'Content-Type': 'application/json'
    //     },
    //     body: JSON.stringify({ name })
    // }).then(response => response.json())
    // .then(data => {
    //     resultDiv.textContent = `Form submitted successfully! Name: ${name}`;
    // });
});
```

#### Python Flask Backend (Optional)
```python
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/save-form-data', methods=['POST'])
def save_form_data():
    data = request.get_json()
    name = data['name']
    with open('data.txt', 'a') as file:
        file.write(f'Name: {name}\n')
    return jsonify({'status': 'success'})

if __name__ == '__main__':
    app.run(debug=True)
```

### Additional Tips
- **Breakout Sessions**: Divide the class into small groups to work on different parts of the project.
- **Peer Review**: Have students review each other's code and forms.
- **Q&A Session**: Allow time for questions and clarifications.

